css:
.loader {
  width: 120px;
  height: 21px;
  background:
    linear-gradient(#000 0 0) left/10px 100% no-repeat
    #ddd;
  animation: l6 1s infinite cubic-bezier(0, 0.2, 1, 1);
  position: relative;
}
.loader:before,
.loader:after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  height: 7px;
  background:
    linear-gradient(#000 0 0) left/10px 100% no-repeat
    #ddd;
  animation: inherit;
}
.loader:before {
  top: 0;
  animation-timing-function: cubic-bezier(0, 0, 1, 1);
}
.loader:after {
  bottom: 0;
  animation-timing-function: cubic-bezier(0, 0.4, 1, 1);
}
@keyframes l6 {
  50% { background-position: right; }
}
